      "path": "src/modules/members/routes.js",
      "content": "const express = require('express');
const router = express.Router();
const membersService = require('./service');

router.post('/:projectId/members', (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) return sendError(res, 400, 'E_BADREQUEST', 'Invalid member data');
  const newMember = membersService.createMember({ projectId: req.params.projectId, userId, role });
  res.status(201).json({ member: newMember });
});"
